 1	import React, { FC, MouseEvent, useMemo, useState } from 'react';
 2	import { useNavigate, useParams } from 'react-router-dom-v5-compat';
 3	
 4	import CreateFromInstanceType from '@catalog/CreateFromInstanceTypes/CreateFromInstanceType';
 5	import TemplatesCatalog from '@catalog/templatescatalog/TemplatesCatalog';
 6	import { ALL_NAMESPACES } from '@kubevirt-utils/hooks/constants';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { Stack, StackItem, Tab, Tabs, Title } from '@patternfly/react-core';
 9	import { CatalogIcon, ImageIcon } from '@patternfly/react-icons';
10	
11	import CreateVMTabTitle from './components/CreateVMTabTitle/CreateVMTabTitle';
12	import { CREATE_VM_TAB } from './constants';
13	
14	import './CreateVMHorizontalNav.scss';
15	
16	const CreateVMHorizontalNav: FC = () => {
17	  const { t } = useKubevirtTranslation();
18	  const navigate = useNavigate();
19	  const params = useParams();
20	  const [currentTab, setCurrentTab] = useState<CREATE_VM_TAB>(
21	    location.pathname.endsWith(CREATE_VM_TAB.TEMPLATE)
22	      ? CREATE_VM_TAB.TEMPLATE
23	      : CREATE_VM_TAB.INSTANCE_TYPES,
24	  );
25	
26	  const catalogURL = useMemo(
27	    () => `/k8s/${params?.ns ? `ns/${params?.ns}` : ALL_NAMESPACES}/catalog`,
28	    [params],
29	  );
30	
31	  const handleTabClick = (_event: MouseEvent, tabIndex: CREATE_VM_TAB) => {
32	    setCurrentTab(tabIndex);
33	    navigate(`${catalogURL}${tabIndex}`);
34	  };
35	
36	  return (
37	    <div className="create-vm-horizontal-nav">
38	      <div className="pf-v6-c-page__main-breadcrumb">
39	        <Stack className="co-m-pane__heading" hasGutter>
40	          <StackItem>
41	            <Title headingLevel="h1">{t('Create new VirtualMachine')}</Title>
42	          </StackItem>
43	          <StackItem>{t('Select an option to create a VirtualMachine from.')}</StackItem>
44	        </Stack>
45	      </div>
46	      <Tabs activeKey={currentTab} onSelect={handleTabClick} usePageInsets>
47	        <Tab
48	          data-test="instancetypes-tab"
49	          eventKey={CREATE_VM_TAB.INSTANCE_TYPES}
50	          title={<CreateVMTabTitle Icon={ImageIcon} titleText={t('InstanceTypes')} />}
51	        >
52	          <CreateFromInstanceType currentTab={currentTab} />
53	        </Tab>
54	        <Tab
55	          data-test="templates-tab"
56	          eventKey={CREATE_VM_TAB.TEMPLATE}
57	          title={<CreateVMTabTitle Icon={CatalogIcon} titleText={t('Template catalog')} />}
58	        >
59	          <TemplatesCatalog currentTab={currentTab} />
60	        </Tab>
61	      </Tabs>
62	    </div>
63	  );
64	};
65	
66	export default CreateVMHorizontalNav;

